SELECT DISTINCT t.type_name
FROM plant_species ps
JOIN types t ON ps.type_id = t.type_id;

SELECT *
FROM plant_species
WHERE sepal_length = (SELECT MAX(sepal_length) FROM plant_species);

SELECT type_name, description
FROM types
WHERE type_id = 1;

SELECT COUNT(*)
FROM plant_species
WHERE species_id = 1;

SELECT AVG(petal_length) AS average_petal_length, type_id
FROM plant_species
GROUP BY type_id;

SELECT ps.species_id, t.type_name
FROM plant_species ps
JOIN types t ON ps.type_id = t.type_id;

SELECT species_id
FROM plant_species
WHERE sepal_width > (SELECT AVG(sepal_width) FROM plant_species);

SELECT sepal_length
FROM plant_species
WHERE species_id = 0;
